package copilot.actions;

import com.intellij.openapi.actionSystem.AnAction;
import com.intellij.openapi.actionSystem.AnActionEvent;
import com.intellij.openapi.actionSystem.CommonDataKeys;
import com.intellij.openapi.editor.Editor;
import com.intellij.openapi.editor.SelectionModel;
import com.intellij.openapi.project.Project;
import com.intellij.openapi.wm.ToolWindow;
import com.intellij.openapi.wm.ToolWindowManager;
import copilot.chat.CopilotChatPanel;
import org.jetbrains.annotations.NotNull;

/**
 * Right-click (or keyboard shortcut) action that opens the Copilot chat window
 * and pre-fills it with the selected text and a prompt.
 *
 * <p>If text is selected: "Explain this code:\n```\n{selection}\n```"
 * <p>If nothing is selected: just opens the chat window.
 */
public class AskCopilotAction extends AnAction {

    @Override
    public void actionPerformed(@NotNull AnActionEvent e) {
        Project project = e.getProject();
        if (project == null) return;

        // Open / focus the Kalynx Copilot tool window
        ToolWindow toolWindow = ToolWindowManager.getInstance(project)
                .getToolWindow("Kalynx Copilot");
        if (toolWindow == null) return;
        toolWindow.show();

        // Pre-fill the input with the selected code (if any)
        Editor editor = e.getData(CommonDataKeys.EDITOR);
        if (editor != null) {
            SelectionModel sel = editor.getSelectionModel();
            if (sel.hasSelection()) {
                String selectedText = sel.getSelectedText();
                if (selectedText != null && !selectedText.isBlank()) {
                    String prompt = "Explain this code:\n```\n" + selectedText + "\n```";
                    // Find the chat panel from the tool window content
                    toolWindow.getContentManager().getContents();
                    if (toolWindow.getContentManager().getContentCount() > 0) {
                        var comp = toolWindow.getContentManager().getContent(0);
                        if (comp != null && comp.getComponent() instanceof CopilotChatPanel panel) {
                            panel.setInputText(prompt);
                        }
                    }
                }
            }
        }
    }

    @Override
    public void update(@NotNull AnActionEvent e) {
        e.getPresentation().setEnabledAndVisible(e.getProject() != null);
    }
}

package copilot.chat;

import com.google.gson.JsonArray;
import com.google.gson.JsonObject;

/**
 * Represents a single message in a conversation.
 * Supports all roles used by the OpenAI chat completions API,
 * including tool-call requests (ASSISTANT) and tool results (TOOL).
 */
public class ChatMessage {

    public enum Role { SYSTEM, USER, ASSISTANT, TOOL }

    private final Role role;
    private final String content;          // null for assistant messages that only have tool_calls
    private JsonArray toolCalls;           // populated when role=ASSISTANT and model called tools
    private String toolCallId;             // populated when role=TOOL
    private String toolName;               // populated when role=TOOL

    private ChatMessage(Role role, String content) {
        this.role = role;
        this.content = content;
    }

    // --- factory helpers ---

    public static ChatMessage system(String content) {
        return new ChatMessage(Role.SYSTEM, content);
    }

    public static ChatMessage user(String content) {
        return new ChatMessage(Role.USER, content);
    }

    public static ChatMessage assistant(String content) {
        return new ChatMessage(Role.ASSISTANT, content);
    }

    /** Assistant message that contains only tool-call requests (no text content). */
    public static ChatMessage assistantWithToolCalls(JsonArray toolCalls) {
        ChatMessage msg = new ChatMessage(Role.ASSISTANT, null);
        msg.toolCalls = toolCalls;
        return msg;
    }

    /** Tool result message returned after executing a tool call. */
    public static ChatMessage toolResult(String toolCallId, String toolName, String content) {
        ChatMessage msg = new ChatMessage(Role.TOOL, content);
        msg.toolCallId = toolCallId;
        msg.toolName = toolName;
        return msg;
    }

    // --- accessors ---

    public Role getRole() { return role; }
    public String getContent() { return content; }
    public JsonArray getToolCalls() { return toolCalls; }
    public String getToolCallId() { return toolCallId; }
    public String getToolName() { return toolName; }
    public boolean hasToolCalls() { return toolCalls != null && toolCalls.size() > 0; }

    /** Serialise to the JSON format expected by the chat completions API. */
    public JsonObject toJson() {
        JsonObject json = new JsonObject();
        json.addProperty("role", role.name().toLowerCase());

        if (content != null) {
            json.addProperty("content", content);
        }

        if (toolCalls != null) {
            json.add("tool_calls", toolCalls);
        }

        if (role == Role.TOOL) {
            json.addProperty("tool_call_id", toolCallId != null ? toolCallId : "");
        }

        return json;
    }
}

package copilot.chat;

import com.intellij.openapi.project.Project;
import com.intellij.openapi.wm.ToolWindow;
import com.intellij.openapi.wm.ToolWindowFactory;
import com.intellij.ui.content.Content;
import com.intellij.ui.content.ContentFactory;
import org.jetbrains.annotations.NotNull;

/**
 * Creates the "Kalynx Copilot" tool window and wires in the chat panel.
 * Registered in plugin.xml as a toolWindow extension.
 */
public class CopilotChatToolWindowFactory implements ToolWindowFactory {

    @Override
    public void createToolWindowContent(@NotNull Project project, @NotNull ToolWindow toolWindow) {
        CopilotChatPanel panel = new CopilotChatPanel(project);
        Content content = ContentFactory.getInstance().createContent(panel, "", false);
        toolWindow.getContentManager().addContent(content);
    }

    @Override
    public boolean shouldBeAvailable(@NotNull Project project) {
        return true;
    }
}
